const posts = $input.first().json.data || [];
return posts.map(p => ({
  json: {
    id: p.id,
    caption: (p.caption || '').substring(0, 200),
    likes: p.like_count || 0,
    comments: p.comment_count || 0,
    media_type: p.media_type,
    permalink: p.permalink,
    timestamp: p.timestamp
  }
}));

const items = $input.all();
if (items.length === 0) return [{ json: { error: 'no_posts', scanned_at: new Date().toISOString() } }];
const totalLikes = items.reduce((s, i) => s + (i.json.likes || 0), 0);
const totalComments = items.reduce((s, i) => s + (i.json.comments || 0), 0);
return [{
  json: {
    hashtag: $env.TARGET_HASHTAG,
    count: items.length,
    total_likes: totalLikes,
    total_comments: totalComments,
    avg_likes: Math.round(totalLikes / items.length),
    avg_comments: Math.round(totalComments / items.length),
    engagement_rate: ((totalLikes + totalComments) / items.length).toFixed(2),
    scanned_at: new Date().toISOString()
  }
}];
